using System.Net;
using Microsoft.AspNetCore.HttpOverrides;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddScoped<IUserService, UserService>();
// Fix 1 (ValidateScopes): Singleton must not consume Scoped services.
// .NET 9 enables ValidateScopes in Development by default, which throws
// InvalidOperationException at startup for this pattern.
// Changed CacheService to Scoped so its lifetime matches IUserService.
builder.Services.AddScoped<ICacheService>(sp =>
    new CacheService(sp.GetRequiredService<IUserService>()));
// Fix 2 (SocketsHttpHandler): .NET 9 HttpClientFactory uses SocketsHttpHandler
// as the default primary handler. The old cast to HttpClientHandler throws
// InvalidCastException. Use ConfigurePrimaryHttpMessageHandler instead.
builder.Services.AddHttpClient("api")
    .ConfigurePrimaryHttpMessageHandler(() =>
        new SocketsHttpHandler { UseCookies = false });
// Fix 3 (Header redaction): .NET 9 redacts ALL header values in Trace-level
// HttpClientFactory logs by default. Allowlist non-sensitive headers you need
// to see in diagnostics.
builder.Services.ConfigureHttpClientDefaults(b =>
    b.RedactLoggedHeaders(h =>
        h != "X-Request-Id"
        && h != "X-Correlation-Id"
        && h != "Cache-Control"
        && h != "Accept"
        && h != "Content-Type"));
// Fix 4 (ForwardedHeaders): .NET 9 ForwardedHeadersMiddleware now silently
// ignores X-Forwarded-* headers from proxies not in KnownProxies/KnownNetworks.
// Configure your reverse proxy address so headers are processed.
builder.Services.Configure<ForwardedHeadersOptions>(options =>
{
    options.ForwardedHeaders = ForwardedHeaders.XForwardedFor;
    // Add the address of your reverse proxy (adjust to your environment)
    options.KnownProxies.Add(IPAddress.Parse("127.0.0.1"));
});
var app = builder.Build();
app.UseForwardedHeaders();
app.Run();

